// ΓòÉΓòÉΓòÉ ANIMATED COUNTER HOOK ΓòÉΓòÉΓòÉ
const useCountUp = (end, duration = 2000, trigger = false) => {
    const [count, setCount] = useState(0);
    const counting = useRef(false);
    useEffect(() => {
        if (!trigger || counting.current) return;
        counting.current = true;
        const start = 0;
        const startTime = performance.now();
        const step = (now) => {
            const elapsed = now - startTime;
            const progress = Math.min(elapsed / duration, 1);
            const ease = 1 - Math.pow(1 - progress, 3); // easeOutCubic
            setCount(Math.round(start + (end - start) * ease));
            if (progress < 1) requestAnimationFrame(step);
        };
        requestAnimationFrame(step);
    }, [trigger, end, duration]);
    return count;
};

// ΓòÉΓòÉΓòÉ FLOATING PARTICLES ΓòÉΓòÉΓòÉ
const Particles = React.memo(() => {
    const [particles] = useState(() =>
        Array.from({ length: 40 }, (_, i) => ({
            id: i,
            x: Math.random() * 100,
            y: Math.random() * 100,
            size: 2 + Math.random() * 4,
            dur: 15 + Math.random() * 25,
            delay: Math.random() * 10,
            opacity: 0.1 + Math.random() * 0.3,
        }))
    );

    return (
        <div className="particles-container" aria-hidden="true">
            {particles.map(p => (
                <div key={p.id} className="particle" style={{
                    left: `${p.x}%`, top: `${p.y}%`,
                    width: p.size, height: p.size,
                    animationDuration: `${p.dur}s`,
                    animationDelay: `${p.delay}s`,
                    opacity: p.opacity,
                }} />
            ))}
        </div>
    );
});

