                                <div className="entropy-bar" style={{ background: `linear-gradient(90deg, ${lvl.color}44, ${lvl.color})`, width: `${(lvl.level / 6) * 100}%` }} />
                            </div>
                        ))}
                    </div>
                    <div className="entropy-diagnosis-box">
                        <h4>≡ƒ⌐║ {t.entropySection.diagnosis}</h4>
