import React, { useState, useEffect } from 'react';
import { Play, Square, Trash2, Circle, ListOrdered } from 'lucide-react';
import toast from 'react-hot-toast';

import { LOCAL_API as API } from '../config.js';

const MacroManager = () => {
    const [macros, setMacros] = useState([]);
    const [recording, setRecording] = useState(false);
    const [macroName, setMacroName] = useState('');

    const fetchMacros = async () => {
        try {
            const res = await fetch(`${API}/macros`);
            const data = await res.json();
            setMacros(data.macros || []);
        } catch (err) {
            console.error("Failed to fetch macros", err);
        }
    };

    useEffect(() => {
        fetchMacros();
    }, []);

    const startRecording = async () => {
        try {
            await fetch(`${API}/macros/record/start`, { method: 'POST' });
            setRecording(true);
            toast.success('Macro recording started');
        } catch {
            toast.error('Failed to start recording');
        }
    };

    const stopRecording = async () => {
        const name = macroName.trim() || `macro_${Date.now()}`;
        try {
            const res = await fetch(`${API}/macros/record/stop`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ name })
            });
            const data = await res.json();
            setRecording(false);
            setMacroName('');
            toast.success(`Macro "${name}" saved (${data.action_count} actions)`);
            fetchMacros();
        } catch {
            toast.error('Failed to stop recording');
        }
    };

    const playMacro = async (name) => {
        toast.loading(`Playing macro: ${name}...`, { id: 'macro-play' });
        try {
            const res = await fetch(`${API}/macros/${name}/play`, { method: 'POST' });
            const data = await res.json();
            toast.dismiss('macro-play');
            if (data.status === 'completed') {
                toast.success(`Macro completed (${data.actions_executed} actions)`);
            } else {
                toast.error(`Macro failed: ${data.message}`);
            }
        } catch {
            toast.dismiss('macro-play');
            toast.error('Macro playback failed');
        }
    };

    const deleteMacro = async (name) => {
        try {
            await fetch(`${API}/macros/${name}`, { method: 'DELETE' });
            toast.success('Macro deleted');
            fetchMacros();
        } catch {
            toast.error('Failed to delete macro');
        }
    };

    return (
        <div className="macro-manager">
            <h3><ListOrdered size={16} /> Macros</h3>

            {/* Record Controls */}
            <div className="macro-record-controls">
                {!recording ? (
                    <button className="btn btn-analyze btn-sm" onClick={startRecording}>
                        <Circle size={12} style={{ color: '#ff5555' }} /> Record
                    </button>
                ) : (
                    <>
                        <input
                            type="text"
                            placeholder="Macro name..."
                            value={macroName}
                            onChange={(e) => setMacroName(e.target.value)}
                            className="macro-name-input"
                        />
                        <button className="btn btn-danger-ghost btn-sm" onClick={stopRecording}>
                            <Square size={12} /> Stop
                        </button>
                        <span className="recording-indicator">ΓùÅ REC</span>
                    </>
                )}
            </div>

            {/* Macro List */}
            <div className="macro-list">
                {macros.length === 0 ? (
                    <p className="no-data">No macros saved.</p>
                ) : (
                    macros.map((m, i) => (
                        <div key={i} className="macro-item">
                            <div className="macro-info">
                                <strong>{m.name}</strong>
                                <small>{m.action_count} actions</small>
                            </div>
                            <div className="macro-actions">
                                <button className="btn btn-ghost btn-sm" onClick={() => playMacro(m.name)} title="Play">
                                    <Play size={14} />
                                </button>
                                <button className="btn btn-danger-ghost btn-sm" onClick={() => deleteMacro(m.name)} title="Delete">
                                    <Trash2 size={14} />
                                </button>
                            </div>
                        </div>
                    ))
                )}
            </div>
        </div>
    );
};

export default MacroManager;

import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { ArrowLeft, Download, FileText, Trash2, Calendar, User, Activity, StickyNote, ClipboardList } from 'lucide-react';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Legend } from 'recharts';
import toast from 'react-hot-toast';
import OrganMap from './OrganMap';
import AIInsights from './AIInsights';
import ComparisonMode from './ComparisonMode';
import '../App.css';

import { API } from '../config.js';

const PatientProfile = () => {
    const { id } = useParams();
    const navigate = useNavigate();
    const [patient, setPatient] = useState(null);
    const [loading, setLoading] = useState(true);
    const [selectedScan, setSelectedScan] = useState(null);
    const [editingNotes, setEditingNotes] = useState('');
    const [report, setReport] = useState(null);
    const [showComparison, setShowComparison] = useState(false);

    const fetchPatient = useCallback(async () => {
        try {
            const res = await fetch(`${API}/patients/${id}`);
            if (!res.ok) throw new Error('Patient not found');
            const data = await res.json();
            setPatient(data);
        } catch {
            toast.error('Failed to load patient');
            navigate('/');
        } finally {
            setLoading(false);
        }
    }, [id, navigate]);

    useEffect(() => {
        fetchPatient();
    }, [fetchPatient]);

    const handleDeleteScan = async (scanId) => {
        if (!confirm('Delete this scan result?')) return;
        try {
            await fetch(`${API}/scans/${scanId}`, { method: 'DELETE' });
            toast.success('Scan deleted');
            fetchPatient();
        } catch {
            toast.error('Failed to delete scan');
        }
    };

    const handleSaveNotes = async (scanId) => {
        try {
            await fetch(`${API}/scans/${scanId}/notes`, {
                method: 'PUT',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ notes: editingNotes })
            });
            toast.success('Notes saved');
            setSelectedScan(null);
            fetchPatient();
        } catch {
            toast.error('Failed to save notes');
        }
    };

    const handleExport = (format) => {
        window.open(`${API}/patients/${id}/export/${format}`, '_blank');
        toast.success(`${format.toUpperCase()} export started`);
    };

    const generateReport = async () => {
        try {
            const res = await fetch(`${API}/patients/${id}/report`);
            const data = await res.json();
            setReport(data);
            toast.success('Health report generated');
        } catch {
            toast.error('Failed to generate report');
        }
    };

    const getStatusClass = (status) => {
        if (!status) return 'normal';
        const s = status.toLowerCase();
        if (s.includes('pathol')) return 'pathology';
        if (s.includes('comprom') || s.includes('stress')) return 'compromised';
        return 'normal';
    };

    // Build chart data from scans
    const getChartData = () => {
        if (!patient?.scans?.length) return [];
        return [...patient.scans].reverse().map((scan, idx) => {
            const counts = scan.counts || {};
            return {
                name: scan.organ_name?.substring(0, 12) || `Scan ${idx + 1}`,
                'Level 1': parseInt(counts['1']) || 0,
                'Level 2': parseInt(counts['2']) || 0,
                'Level 3': parseInt(counts['3']) || 0,
                'Level 4': parseInt(counts['4']) || 0,
                'Level 5': parseInt(counts['5']) || 0,
                'Level 6': parseInt(counts['6']) || 0,
                total: scan.total_points || 0,
            };
        });
    };

    if (loading) {
        return (
            <div className="profile-page">
                <div className="skeleton" style={{ height: 40, width: 200, marginBottom: 20 }} />
                <div className="skeleton" style={{ height: 200 }} />
            </div>
        );
    }

    if (!patient) return null;

    const chartColors = ['#50fa7b', '#b8e986', '#f1fa8c', '#ffb86c', '#ff7979', '#ff5555'];

    return (
        <div className="profile-page">
            {/* Header */}
            <div className="profile-header">
                <div className="profile-info">
                    <button className="back-btn" onClick={() => navigate('/')}>
                        <ArrowLeft size={16} /> Back to Dashboard
                    </button>
                    <h1>{patient.name}</h1>
                    <div className="profile-meta">
                        <span><User size={14} /> {patient.age} yrs, {patient.gender}</span>
                        <span><Calendar size={14} /> Since {new Date(patient.created_at).toLocaleDateString()}</span>
                        <span><Activity size={14} /> {patient.scan_count} scans</span>
                    </div>
                </div>
                <div className="profile-actions">
                    <button className="btn btn-outline btn-sm" onClick={() => handleExport('csv')}>
                        <FileText size={14} /> CSV
                    </button>
                    <button className="btn btn-outline btn-sm" onClick={() => handleExport('pdf')}>
                        <Download size={14} /> PDF
                    </button>
                    <button className="btn btn-analyze btn-sm" onClick={generateReport}>
                        <ClipboardList size={14} /> Report
                    </button>
                    <button className="btn btn-outline btn-sm" onClick={() => window.open(`${API}/patients/${id}/export/dicom`)}>
                        ≡ƒÅÑ DICOM
                    </button>
                    <button className="btn btn-ghost btn-sm" onClick={() => {
                        const email = prompt('Send report to email:');
                        if (email) {
                            fetch(`${API}/patients/${id}/email-report`, {
                                method: 'POST',
                                headers: { 'Content-Type': 'application/json' },
                                body: JSON.stringify({ email })
                            }).then(r => r.json()).then(d => {
                                if (d.status === 'sent') toast.success('Report sent!');
                                else toast.success(`Report preview generated (SMTP not configured)`);
                            }).catch(() => toast.error('Failed to send'));
                        }
                    }}>
                        Γ£ë∩╕Å Email
                    </button>
                    <button className="btn btn-ghost btn-sm" onClick={() => setShowComparison(true)}>
                        ≡ƒöÇ Compare
                    </button>
                </div>
            </div>

            {showComparison && (
                <ComparisonMode patientId={id} onClose={() => setShowComparison(false)} />
            )}

            {/* Health Report */}
            {report && (
                <div className="health-report">
                    <h3>Health Report</h3>
                    <p className="report-summary">{report.summary}</p>
                    <div className="report-recommendations">
                        {report.recommendations?.map((r, i) => (
                            <div key={i} className="recommendation-item">{r}</div>
                        ))}
                    </div>
                    <button className="btn btn-ghost btn-sm" onClick={() => setReport(null)} style={{ marginTop: 8 }}>Close Report</button>
                </div>
            )}

            {/* Organ Map */}
            <OrganMap patientId={id} scanResults={patient.scans} />

            {/* AI Insights */}
            <AIInsights scanId={selectedScan?.id || patient.scans?.[0]?.id} patientId={id} />

            {/* Content Grid */}
            <div className="profile-content">
                {/* Entropy Trends Chart */}
                <div className="profile-section">
                    <h2><Activity size={18} /> Entropy Trends</h2>
                    {patient.scans?.length > 0 ? (
                        <div className="chart-container">
                            <ResponsiveContainer width="100%" height="100%">
                                <LineChart data={getChartData()}>
                                    <CartesianGrid strokeDasharray="3 3" stroke="rgba(255,255,255,0.06)" />
                                    <XAxis
                                        dataKey="name"
                                        tick={{ fill: '#8892a4', fontSize: 11 }}
                                        axisLine={{ stroke: 'rgba(255,255,255,0.1)' }}
                                    />
                                    <YAxis
                                        tick={{ fill: '#8892a4', fontSize: 11 }}
                                        axisLine={{ stroke: 'rgba(255,255,255,0.1)' }}
                                    />
                                    <Tooltip
                                        contentStyle={{
                                            background: '#1a1a2e',
                                            border: '1px solid rgba(255,255,255,0.1)',
                                            borderRadius: 8,
                                            color: '#e2e8f0'
                                        }}
                                    />
                                    <Legend />
                                    {[1, 2, 3, 4, 5, 6].map((level, i) => (
                                        <Line
                                            key={level}
                                            type="monotone"
                                            dataKey={`Level ${level}`}
                                            stroke={chartColors[i]}
                                            strokeWidth={2}
                                            dot={{ r: 3 }}
                                            activeDot={{ r: 5 }}
                                        />
                                    ))}
                                </LineChart>
                            </ResponsiveContainer>
                        </div>
                    ) : (
                        <p className="no-data">No scan data yet. Run a scan from the dashboard.</p>
                    )}
                </div>

                {/* Scan History */}
                <div className="profile-section">
                    <h2><FileText size={18} /> Scan History</h2>
                    {patient.scans?.length > 0 ? (
                        <div className="scan-timeline">
                            {patient.scans.map(scan => (
                                <div
                                    key={scan.id}
                                    className="scan-card"
                                    onClick={() => {
                                        setSelectedScan(scan);
                                        setEditingNotes(scan.practitioner_notes || '');
                                    }}
                                >
                                    <div className="scan-card-info">
                                        <span className="organ-name">{scan.organ_name}</span>
                                        <span className="scan-date">
                                            {scan.timestamp ? new Date(scan.timestamp).toLocaleString() : 'N/A'}
                                        </span>
                                        <span className={`scan-status ${getStatusClass(scan.status)}`}>
                                            {scan.status}
                                        </span>
                                    </div>
                                    <div className="scan-card-actions">
                                        <button
                                            className="btn btn-danger-ghost"
                                            onClick={(e) => {
                                                e.stopPropagation();
                                                handleDeleteScan(scan.id);
                                            }}
                                        >
                                            <Trash2 size={14} />
                                        </button>
                                    </div>
                                </div>
                            ))}
                        </div>
                    ) : (
                        <p className="no-data">No scan history available.</p>
                    )}
                </div>
            </div>

            {/* Scan Detail Modal */}
            {selectedScan && (
                <div className="scan-detail-overlay" onClick={() => setSelectedScan(null)}>
                    <div className="scan-detail-modal" onClick={(e) => e.stopPropagation()}>
                        <button className="modal-close" onClick={() => setSelectedScan(null)}>Γ£ò</button>
                        <h3>{selectedScan.organ_name}</h3>
                        <p className="status-text">
                            {selectedScan.status} ΓÇó {selectedScan.total_points} points ΓÇó{' '}
                            {selectedScan.timestamp ? new Date(selectedScan.timestamp).toLocaleString() : ''}
                        </p>

                        <div className="entropy-grid" style={{ marginBottom: 16 }}>
                            {Object.entries(selectedScan.counts || {}).map(([lvl, count]) => (
                                <div key={lvl} className={`entropy-item lvl-${lvl}`}>
                                    <span>Lvl {lvl}</span>
                                    <strong>{count}</strong>
                                </div>
                            ))}
                        </div>

                        <h4 style={{ margin: '0 0 8px', fontSize: '0.9rem', color: '#8892a4', display: 'flex', alignItems: 'center', gap: 6 }}>
                            <StickyNote size={14} /> Practitioner Notes
                        </h4>
                        <textarea
                            className="scan-notes-textarea"
                            value={editingNotes}
                            onChange={(e) => setEditingNotes(e.target.value)}
                            placeholder="Add notes about this scan..."
                        />
                        <div style={{ display: 'flex', gap: 8, marginTop: 12, justifyContent: 'flex-end' }}>
                            <button className="btn btn-ghost btn-sm" onClick={() => setSelectedScan(null)}>Cancel</button>
                            <button className="btn btn-analyze btn-sm" onClick={() => handleSaveNotes(selectedScan.id)}>
                                Save Notes
                            </button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default PatientProfile;

import React, { useState, useEffect, useRef } from 'react';
import { Eye, EyeOff, Radio, ChevronDown, ChevronRight, FileText, BarChart3, Tag, Clipboard, Type, Activity, Gauge } from 'lucide-react';
import toast from 'react-hot-toast';

import { LOCAL_API as API } from '../config.js';

const ScreenWatcherPanel = ({ patientId }) => {
    const [watching, setWatching] = useState(false);
    const [events, setEvents] = useState([]);
    const [lastEventId, setLastEventId] = useState(0);
    const [totalChanges, setTotalChanges] = useState(0);
    const [expandedEvent, setExpandedEvent] = useState(null);
    const pollRef = useRef(null);

    // Poll for new events while watching
    useEffect(() => {
        if (watching) {
            pollRef.current = setInterval(async () => {
                try {
                    const res = await fetch(`${API}/watcher/events?since_id=${lastEventId}&limit=20`);
                    const data = await res.json();
                    if (data.events && data.events.length > 0) {
                        setEvents(prev => [...data.events, ...prev].slice(0, 100));
                        const maxId = Math.max(...data.events.map(e => e.id));
                        setLastEventId(maxId);
                        setTotalChanges(data.total_changes);
                        data.events.forEach(evt => {
                            const organ = evt.organ_detected || 'Screen change';
                            const rows = evt.nls_readings?.row_count || 0;
                            toast(`≡ƒöì ${organ}${rows > 0 ? ` ΓÇö ${rows} readings` : ''}`, {
                                icon: '≡ƒôí', duration: 3000
                            });
                        });
                    }
                } catch (e) {
                    console.error('Watcher poll error:', e);
                }
            }, 2000);
        }
        return () => { if (pollRef.current) clearInterval(pollRef.current); };
    }, [watching, lastEventId]);

    // Check watcher status on mount
    useEffect(() => {
        (async () => {
            try {
                const res = await fetch(`${API}/watcher/status`);
                const data = await res.json();
                setWatching(data.running);
                setTotalChanges(data.total_changes || 0);
            } catch (e) { /* backend offline */ }
        })();
    }, []);

    const handleToggle = async () => {
        try {
            if (watching) {
                const res = await fetch(`${API}/watcher/stop`, { method: 'POST' });
                const data = await res.json();
                setWatching(false);
                toast.success(`Watcher stopped ΓÇö ${data.total_changes} changes captured`);
            } else {
                const res = await fetch(`${API}/watcher/start`, {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({ patient_id: patientId })
                });
                await res.json();
                setWatching(true);
                setLastEventId(0);
                toast.success('Auto-watcher started ΓÇö monitoring for NLS screen changes');
            }
        } catch (e) {
            toast.error('Failed to toggle watcher');
        }
    };

    const toggleExpand = (id) => {
        setExpandedEvent(expandedEvent === id ? null : id);
    };

    return (
        <div className={`watcher-panel ${watching ? 'watching-active' : ''}`}>
            <div className="watcher-header">
                <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
                    <h3><Eye size={14} className={watching ? 'pulse-icon' : ''} /> Auto Watcher</h3>
                    {watching && (
                        <span className="watcher-live-badge">
                            <Radio size={10} className="pulse-icon" /> LIVE
                        </span>
                    )}
                </div>
                <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
                    {totalChanges > 0 && (
                        <span className="watcher-count">
                            <Activity size={10} /> {totalChanges} changes
                        </span>
                    )}
                    <button
                        className={`btn btn-sm ${watching ? 'btn-danger' : 'btn-primary'}`}
                        onClick={handleToggle}
                    >
                        {watching ? <><EyeOff size={12} /> Stop</> : <><Eye size={12} /> Start Watching</>}
                    </button>
                </div>
            </div>

            {events.length > 0 ? (
                <div className="watcher-events">
                    {events.map(evt => (
                        <div
                            key={evt.id}
                            className={`watcher-event ${expandedEvent === evt.id ? 'expanded' : ''}`}
                            onClick={() => toggleExpand(evt.id)}
                        >
                            <div className="watcher-event-header">
                                <span className="watcher-event-time">
                                    {new Date(evt.timestamp).toLocaleTimeString()}
                                </span>
                                <span className="watcher-event-organ">
                                    {evt.organ_detected || 'Screen Change'}
                                </span>
                                <span className="watcher-event-change">
                                    {evt.change_pct}%
                                </span>
                                {evt.nls_readings?.row_count > 0 && (
                                    <span className="watcher-event-rows">
                                        {evt.nls_readings.row_count} rows
                                    </span>
                                )}
                                <span className={`watcher-event-status status-${evt.analysis?.status?.includes('Normal') ? 'normal' : 'alert'}`}>
                                    {evt.analysis?.total_points || 0} pts
                                </span>
                                {expandedEvent === evt.id ? <ChevronDown size={14} /> : <ChevronRight size={14} />}
                            </div>

                            {/* Summary line */}
                            {evt.summary && (
                                <div className="watcher-event-summary">{evt.summary}</div>
                            )}

                            {expandedEvent === evt.id && (
                                <div className="watcher-event-details">
                                    {/* NLS Readings Table */}
                                    {evt.nls_readings?.rows?.length > 0 && (
                                        <div className="watcher-detail-section">
                                            <h5><Clipboard size={12} /> NLS Organ Readings</h5>
                                            <div className="nls-readings-table">
                                                {evt.nls_readings.rows.map((row, i) => (
                                                    <div key={i} className="nls-reading-row">
                                                        <span className="nls-code">{row.code}</span>
                                                        <span className="nls-desc">{row.description}</span>
                                                    </div>
                                                ))}
                                            </div>
                                        </div>
                                    )}

                                    {/* Reserve % */}
                                    {evt.nls_readings?.reserve_pct != null && (
                                        <div className="watcher-detail-section">
                                            <h5><Gauge size={12} /> Compensatory Reserve</h5>
                                            <div className="reserve-bar-container">
                                                <div className="reserve-bar" style={{ width: `${evt.nls_readings.reserve_pct}%` }}></div>
                                                <span className="reserve-label">{evt.nls_readings.reserve_pct}%</span>
                                            </div>
                                        </div>
                                    )}

                                    {/* NLS Keywords */}
                                    {evt.nls_readings?.keywords?.length > 0 && (
                                        <div className="watcher-detail-section">
                                            <h5><Tag size={12} /> Keywords Detected</h5>
                                            <div className="keyword-tags">
                                                {evt.nls_readings.keywords.slice(0, 10).map((kw, i) => (
                                                    <span key={i} className="keyword-tag">{kw}</span>
                                                ))}
                                            </div>
                                        </div>
                                    )}

                                    {/* Entropy Analysis */}
                                    <div className="watcher-detail-section">
                                        <h5><BarChart3 size={12} /> Entropy Analysis</h5>
                                        <p><strong>Status:</strong> {evt.analysis?.status}</p>
                                        <p><strong>Total Points:</strong> {evt.analysis?.total_points}</p>
                                        {evt.analysis?.counts && (
                                            <div className="entropy-grid mini">
                                                {Object.entries(evt.analysis.counts).map(([lvl, count]) => (
                                                    <div key={lvl} className={`entropy-item lvl-${lvl}`}>
                                                        <span>L{lvl}</span>
                                                        <strong>{count}</strong>
                                                    </div>
                                                ))}
                                            </div>
                                        )}
                                    </div>

                                    {/* Status bar text */}
                                    {evt.status_bar && (
                                        <div className="watcher-detail-section">
                                            <h5><FileText size={12} /> Status Bar</h5>
                                            <p className="status-bar-text">{evt.status_bar}</p>
                                        </div>
                                    )}

                                    {/* Raw OCR (collapsed by default) */}
                                    {evt.ocr_text && (
                                        <details className="watcher-detail-section">
                                            <summary className="ocr-toggle"><Type size={12} /> Raw OCR Text</summary>
                                            <pre className="watcher-ocr-text">{evt.ocr_text}</pre>
                                        </details>
                                    )}
                                </div>
                            )}
                        </div>
                    ))}
                </div>
            ) : (
                <div className="watcher-empty">
                    {watching
                        ? <><Eye size={16} className="pulse-icon" /> Watching for NLS screen changes...</>
                        : 'Start watching to auto-detect organ changes and capture NLS data'
                    }
                </div>
            )}
        </div>
    );
};

export default ScreenWatcherPanel;

