import React, { useState, useEffect } from 'react';
import { Users, Shield, Clock, LogOut, UserCheck, UserX } from 'lucide-react';
import toast from 'react-hot-toast';

import { API } from '../config.js';

const SettingsPanel = ({ user, token, onLogout }) => {
    const [users, setUsers] = useState([]);
    const [auditLogs, setAuditLogs] = useState([]);
    const [activeTab, setActiveTab] = useState('profile');

    const authHeaders = {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${token}`
    };

    useEffect(() => {
        if (activeTab === 'users') fetchUsers();
        if (activeTab === 'audit') fetchAuditLogs();
    }, [activeTab]);

    const fetchUsers = async () => {
        try {
            const res = await fetch(`${API}/users`, { headers: authHeaders });
            const data = await res.json();
            setUsers(data);
        } catch { console.error('Failed to fetch users'); }
    };

    const fetchAuditLogs = async () => {
        try {
            const res = await fetch(`${API}/audit?limit=30`, { headers: authHeaders });
            const data = await res.json();
            setAuditLogs(data);
        } catch { console.error('Failed to fetch audit logs'); }
    };

    const toggleUser = async (userId) => {
        try {
            const res = await fetch(`${API}/users/${userId}/toggle`, {
                method: 'POST',
                headers: authHeaders
            });
            if (res.ok) {
                toast.success('User status updated');
                fetchUsers();
            } else {
                const data = await res.json();
                toast.error(data.error || 'Failed to update user');
            }
        } catch { toast.error('Failed to update user'); }
    };

    const getRoleBadge = (role) => {
        const colors = { admin: '#ff5555', practitioner: '#bd93f9', viewer: '#8be9fd' };
        return (
            <span className="role-badge" style={{ background: `${colors[role]}22`, color: colors[role], border: `1px solid ${colors[role]}44` }}>
                {role}
            </span>
        );
    };

    return (
        <div className="settings-panel">
            <div className="settings-tabs">
                <button className={`cv-tab ${activeTab === 'profile' ? 'active' : ''}`} onClick={() => setActiveTab('profile')}>
                    <Shield size={14} /> Profile
                </button>
                {user?.role === 'admin' && (
                    <button className={`cv-tab ${activeTab === 'users' ? 'active' : ''}`} onClick={() => setActiveTab('users')}>
                        <Users size={14} /> Users
                    </button>
                )}
                <button className={`cv-tab ${activeTab === 'audit' ? 'active' : ''}`} onClick={() => setActiveTab('audit')}>
                    <Clock size={14} /> Audit
                </button>
            </div>

            {/* Profile Tab */}
            {activeTab === 'profile' && user && (
                <div className="settings-content">
                    <div className="profile-card-settings">
                        <div className="profile-avatar">{user.full_name?.[0] || user.username[0]}</div>
                        <div>
                            <h3>{user.full_name || user.username}</h3>
                            <p>{user.email}</p>
                            {getRoleBadge(user.role)}
                        </div>
                    </div>
                    <div className="profile-details">
                        <div className="detail-row"><span>Username</span><span>{user.username}</span></div>
                        <div className="detail-row"><span>Role</span><span>{user.role}</span></div>
                        <div className="detail-row"><span>Member since</span><span>{new Date(user.created_at).toLocaleDateString()}</span></div>
                        <div className="detail-row"><span>Last login</span><span>{user.last_login ? new Date(user.last_login).toLocaleString() : 'N/A'}</span></div>
                    </div>
                    <button className="btn btn-danger-ghost btn-sm" onClick={onLogout} style={{ marginTop: 16 }}>
                        <LogOut size={14} /> Sign Out
                    </button>
                </div>
            )}

            {/* Users Tab (Admin only) */}
            {activeTab === 'users' && (
                <div className="settings-content">
                    <div className="user-list-admin">
                        {users.map(u => (
                            <div key={u.id} className={`user-row ${!u.is_active ? 'inactive' : ''}`}>
                                <div className="user-row-info">
                                    <strong>{u.full_name || u.username}</strong>
                                    <small>{u.email}</small>
                                </div>
                                {getRoleBadge(u.role)}
                                {u.id !== user?.id && (
                                    <button
                                        className="btn btn-ghost btn-sm"
                                        onClick={() => toggleUser(u.id)}
                                        title={u.is_active ? 'Deactivate' : 'Activate'}
                                    >
                                        {u.is_active ? <UserX size={14} /> : <UserCheck size={14} />}
                                    </button>
                                )}
                            </div>
                        ))}
                    </div>
                </div>
            )}

            {/* Audit Tab */}
            {activeTab === 'audit' && (
                <div className="settings-content">
                    <div className="audit-list">
                        {auditLogs.length === 0 ? (
                            <p className="no-data">No audit events yet.</p>
                        ) : (
                            auditLogs.map(log => (
                                <div key={log.id} className="audit-item">
                                    <div className="audit-action">{log.action}</div>
                                    <div className="audit-meta">
                                        <span>{log.username || 'System'}</span>
                                        <span>{log.entity_type}{log.entity_id ? ` #${log.entity_id.substring(0, 8)}` : ''}</span>
                                        <small>{new Date(log.timestamp).toLocaleString()}</small>
                                    </div>
                                </div>
                            ))
                        )}
                    </div>
                </div>
            )}
        </div>
    );
};

export default SettingsPanel;

import React, { useState, useEffect, useRef } from 'react';
import { Users, Activity, Zap, Wifi, TrendingUp, TrendingDown } from 'lucide-react';

import { API } from '../config.js';

/** Animated number counter */
const AnimatedCounter = ({ value, duration = 800 }) => {
    const [display, setDisplay] = useState(0);
    const ref = useRef(null);

    useEffect(() => {
        if (typeof value !== 'number') return;
        const start = display;
        const diff = value - start;
        if (diff === 0) return;
        const startTime = performance.now();

        const tick = (now) => {
            const elapsed = now - startTime;
            const progress = Math.min(elapsed / duration, 1);
            // cubic ease-out
            const eased = 1 - Math.pow(1 - progress, 3);
            setDisplay(Math.round(start + diff * eased));
            if (progress < 1) ref.current = requestAnimationFrame(tick);
        };
        ref.current = requestAnimationFrame(tick);
        return () => cancelAnimationFrame(ref.current);
    }, [value]);

    return <span className="animated-number">{display}</span>;
};

const StatsWidgets = () => {
    const [stats, setStats] = useState(null);
    const [prevStats, setPrevStats] = useState(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        fetchStats();
        const interval = setInterval(fetchStats, 10000);
        return () => clearInterval(interval);
    }, []);

    const fetchStats = async () => {
        try {
            const res = await fetch(`${API}/stats`);
            const data = await res.json();
            setPrevStats(stats);
            setStats(data);
        } catch (err) {
            console.error("Failed to fetch stats:", err);
        } finally {
            setLoading(false);
        }
    };

    if (loading) {
        return (
            <div className="stats-grid">
                {[1, 2, 3, 4].map(i => (
                    <div key={i} className="stat-card skeleton skeleton-stat" />
                ))}
            </div>
        );
    }

    const getTrend = (key) => {
        if (!prevStats || !stats) return null;
        const curr = stats[key] ?? 0;
        const prev = prevStats[key] ?? 0;
        if (curr > prev) return 'up';
        if (curr < prev) return 'down';
        return null;
    };

    const widgets = [
        {
            icon: <Users size={20} />,
            value: stats?.total_patients ?? 0,
            label: 'Total Patients',
            theme: 'accent',
            trend: getTrend('total_patients'),
            isNumeric: true,
        },
        {
            icon: <Activity size={20} />,
            value: stats?.total_scans ?? 0,
            label: 'Total Scans',
            theme: 'success',
            trend: getTrend('total_scans'),
            isNumeric: true,
        },
        {
            icon: <Zap size={20} />,
            value: stats?.scans_today ?? 0,
            label: 'Scans Today',
            theme: 'info',
            trend: getTrend('scans_today'),
            isNumeric: true,
        },
        {
            icon: <Wifi size={20} />,
            value: stats?.bot_online ? 'Online' : 'Offline',
            label: 'NLS System',
            theme: stats?.bot_online ? 'success' : 'warning',
            isNumeric: false,
            statusDot: true,
        }
    ];

    return (
        <div className="stats-grid">
            {widgets.map((w, idx) => (
                <div key={idx} className={`stat-card ${w.theme}`} style={{ animationDelay: `${idx * 60}ms` }}>
                    <div className="stat-icon">{w.icon}</div>
                    <div className="stat-value">
                        {w.isNumeric ? <AnimatedCounter value={w.value} /> : (
                            <span className="stat-status-text">
                                {w.statusDot && <span className={`stat-live-dot ${stats?.bot_online ? 'online' : 'offline'}`} />}
                                {w.value}
                            </span>
                        )}
                    </div>
                    <div className="stat-label">
                        {w.label}
                        {w.trend === 'up' && <TrendingUp size={12} className="trend-icon trend-up" />}
                        {w.trend === 'down' && <TrendingDown size={12} className="trend-icon trend-down" />}
                    </div>
                </div>
            ))}
        </div>
    );
};

export default StatsWidgets;
